<template>
   <div>
      <header class="zqd">
         <p>
            <van-icon name="arrow-left" @click="fan()" />
         </p>
         <p>{{ a }}</p>
         <p>切换城市</p>
      </header>
      <p class="p1">
         <input type="text" placeholder="请输入" v-model="kew" @keyup.enter="add()"> <br>
         <van-button type="primary" @click="add()">提交</van-button> <br>
      </p>
      <span class="sp1">历史搜索</span> <span @click="clear()">清空</span> <br>
      <ul>
         <li class="lib" v-for="(item,index) in list"  @click="zqd_dian(item)">
            <p>{{ item.name }}</p>
            <span>{{ item.address }}</span>
         </li>
      </ul>

      <section>
         <ul>
            <li class="lib" v-for="(item,index) in arr" @click="zqd_dian(item)">
               <p>{{ item.name }}</p>
               <span>{{ item.address }}</span>
            </li>
         </ul>
      </section>
   </div>
</template>

<script>
   export default {
      data() {
         return {
            a: sessionStorage.getItem('a')||'',
            kew: '',
            arr: [],
            list:JSON.parse(localStorage.getItem('ben'))||[]
         }
      },
      created() {
//
      },
      mounted() {


      },
      methods: {
         fan() {
            this.$router.go(-1)
         },
         async add() {
            if (this.kew == "") {
               alert('请输入')
               return false
            }
            let { data } = await this.$http.get(`http://elm.cangdu.org/v1/pois?type=search&city_id=${this.$route.query.data.id}&keyword=${this.kew}`)
            // console.log(data)
            this.arr = data
         },
         async zqd_dian(i) {
            this.list.unshift(i)
              if (this.list.length > 5) {
               this.list.pop()
            }
            localStorage.setItem('ben', JSON.stringify(this.list))
            //let {data} = await this.$http.get(`http://elm.cangdu.org/v2/index_entry?geohash=35.267538,113.691557&group_type=1&flags[]=F`)
            // console.log(data)
            this.$router.push({
               path:'/qiang',
            })

         },
         clear(){
            this.list=[]
            localStorage.clear()

         }
      },

   };
</script>

<style scoped>
   .zqd {
      display: flex;
      justify-content: space-between;
      font-size: 15px;
      background: cornflowerblue;
      color: #fff;
      line-height: 50px;
   }

   .p1 {
      line-height: 50px;
      text-align: center;
   }

   .p1>input {
      width: 270px;
      height: 30px;
   }

   section {
      padding: 0 20px;
   }

   .lib {
      width: 100%;
   }

   .lib>p {
      font-size: 20px
   }

   .lib>span {
      font-size: 16px;
      color: #ccc;
   }

   .sp1 {
      color: #808080;
      font-size: 10px;
   }
</style>